  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee student visa approval?","a":"No. Embassy decides based on admission, funds, and credibility. Never promise approval."},{"q":"What is APS?","a":"Academic Evaluation Centre verification for Indian academic documents—mandatory for most Indian student visa applicants."},{"q":"Blocked account amount for 2026?","a":"Typically €11,904 (12 months × €992). Verify current amount before opening account."},{"q":"Can spouse accompany?","a":"Dependants may apply separately; prove additional funds and accommodation. Assess case-by-case."},{"q":"English-taught programs need German?","a":"Depends on program—follow admission and embassy requirements."},{"q":"How long to convert to residence permit?","a":"Apply at Ausländerbehörde soon after arrival and registration."},{"q":"Can I work on student visa?","a":"Limited working hours permitted—verify current rules for students in Germany."},{"q":"What after graduation?","a":"Discuss 18-month job-seeker residence permit or Opportunity Card separately."},{"q":"What is Description for this service?","a":"National visa (Type D) for study at a recognised German university or preparatory course. After entry, convert to residence permit at local Ausländerbehörde."},{"q":"What is Eligible applicants for this service?","a":"University admission (Zulassung) or conditional admission · Blocked account or scholarship · APS certificate (India) · Health insurance · Motivation letter"},{"q":"What is Blocked account for this service?","a":"€11,904 for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"Important note on Blocked account?","a":"€11,904 for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"What is Key authority for this service?","a":"German Embassy/Consulate in India · Federal Foreign Office · Local Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Germany; register address; apply for residence permit at Ausländerbehörde within visa validity."},{"q":"Is Admission from recognised German institution required?","a":"Admission from recognised German institution is typically required."},{"q":"Is APS certificate (India) required?","a":"Apply early—processing takes weeks"},{"q":"Is Blocked account or financial proof required?","a":"€11,904 for 2026 or equivalent"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"German or English per program"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"6–12w — After complete file + APS"},{"q":"What is the Government fee?","a":"€75 — + blocked account €11,904"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"15 — + APS & blocked account"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has APS not completed?","a":"Complete APS before embassy slot; track processing on APS website"},{"q":"Why is APS not completed a problem?","a":"Visa appointment booked without APS certificate."},{"q":"What if the client has Insufficient blocked account?","a":"Open blocked account at approved bank for full required amount"},{"q":"Why is Insufficient blocked account a problem?","a":"Amount below required monthly sum or not from recognised provider."}]'::jsonb
